from dataclasses import dataclass, field
from typing import Callable, Optional
import re
import json

@dataclass
class ValidationResult:
    passed: bool
    score: float  # 0.0 = definitely bad, 1.0 = definitely good
    flags: list[str] = field(default_factory=list)
    details: dict = field(default_factory=dict)

class AgentOutputValidator:
    def __init__(self):
        self.rules: list[tuple[str, Callable]] = []
        self._register_default_rules()

    def _register_default_rules(self):
        self.rules = [
            ("non_empty", self._check_non_empty),
            ("no_refusal", self._check_no_refusal),
            ("no_hallucination_markers", self._check_hallucination_markers),
            ("reasonable_length", self._check_reasonable_length),
            ("no_prompt_leak", self._check_prompt_leak),
        ]

    def _check_non_empty(self, output: str, context: dict) -> tuple[bool, str]:
        if not output or len(output.strip()) < 10:
            return False, "Output is empty or too short"
        return True, ""

    def _check_no_refusal(self, output: str, context: dict) -> tuple[bool, str]:
        refusal_patterns = [
            r"i cannot (help|assist|provide)",
            r"i'm (unable|not able) to",
            r"i don't have (access|the ability)",
            r"as an ai (language model|assistant), i"
        ]
        output_lower = output.lower()
        for pattern in refusal_patterns:
            if re.search(pattern, output_lower):
                return False, f"Detected refusal pattern: {pattern}"
        return True, ""

    def _check_hallucination_markers(self, output: str, context: dict) -> tuple[bool, str]:
        # Check for contradictions with known facts in context
        markers = [
            r"as of my (knowledge cutoff|last update)",
            r"i (believe|think|assume) (but am not sure|but cannot confirm)",
        ]
        for pattern in markers:
            if re.search(pattern, output.lower()):
                return False, f"Possible hallucination marker: {pattern}"
        return True, ""

    def _check_reasonable_length(self, output: str, context: dict) -> tuple[bool, str]:
        expected_min = context.get("min_length", 20)
        expected_max = context.get("max_length", 4000)
        length = len(output)
        if length < expected_min:
            return False, f"Output too short: {length} chars (min: {expected_min})"
        if length > expected_max:
            return False, f"Output too long: {length} chars (max: {expected_max})"
        return True, ""

    def _check_prompt_leak(self, output: str, context: dict) -> tuple[bool, str]:
        system_prompt = context.get("system_prompt", "")
        if system_prompt and len(system_prompt) > 50:
            # Check if large chunks of system prompt appear in output
            chunks = [system_prompt[i:i+50] for i in range(0, len(system_prompt)-50, 25)]
            for chunk in chunks[:10]:  # Check first 10 chunks
                if chunk.lower() in output.lower():
                    return False, "Possible system prompt leakage detected"
        return True, ""

    def validate(self, output: str, context: dict = {}) -> ValidationResult:
        flags = []
        passed_count = 0

        for rule_name, rule_fn in self.rules:
            passed, message = rule_fn(output, context)
            if passed:
                passed_count += 1
            else:
                flags.append(f"{rule_name}: {message}")

        score = passed_count / len(self.rules)
        overall_passed = score >= 0.8  # Pass if 80%+ rules pass

        return ValidationResult(
            passed=overall_passed,
            score=round(score, 3),
            flags=flags,
            details={"rules_passed": passed_count, "rules_total": len(self.rules)}
        )

# Usage with logging
validator = AgentOutputValidator()

def validate_and_log(output: str, session_id: str, context: dict, logger) -> str:
    result = validator.validate(output, context)

    log_entry = {
        "event": "output.validation",
        "session_id": session_id,
        "validation_passed": result.passed,
        "quality_score": result.score,
        "flags": result.flags,
        "details": result.details
    }

    if not result.passed:
        logger.warning(json.dumps(log_entry))
    else:
        logger.info(json.dumps(log_entry))

    return output
